Method.Source:
/// <summary>
/// Builds a comma separated line from the values of a container.
/// </summary>
/// <param name = "_values">The values that must be concatenated.</param>
/// <returns>A comma separated line.</returns>
public static server str buildLine(container _values)
{
    str result;

    new InteropPermission(InteropKind::ClrInterop).assert();

    try
    {
        StringBuilder builder = new StringBuilder();
        int           i;

        for (i = 1; i <= conLen(_values); i++)
        {
            if (i > 1)
            {
                builder.Append(',');
            }

            builder.Append(any2Str(conPeek(_values, i)));
        }

        result = builder.ToString();
    }
    catch (Exception::CLRError)
    {
        System.Exception clrException = CLRInterop::getLastException();

        error(strFmt("@Contoso:DemoInteropCsvClrError", clrException.get_Message()));
    }
    finally
    {
        CodeAccessPermission::revertAssert();
    }

    return result;
}
